import re
from pathlib import Path

import pytest

AC_UID = "ae27fa65e816b0dc"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
TARGET = REPO_ROOT / "agents" / "style-inspector.md"

HEADING_RE = re.compile(r"^#### Active CJK Detection Algorithm$", re.MULTILINE)
NEXT_HEADING_RE = re.compile(r"^####|^###", re.MULTILINE)
POS_INVARIANT = "MUST NOT skip CJK scanning for any in-scope file"
ORDERING_TOKENS = ["collect all U+4E00", "classify", "exemption", "report"]
ANCHOR_BEFORE = "**Unconditional scan (exception to --changed-files scoping)**"
ANCHOR_AFTER = "**Exemption (verbatim user-binding quotes)**"


def test_AC_02():
    """
    GIVEN: agents/style-inspector.md is read
    WHEN:  The file is grepped for the heading anchor '^#### Active CJK Detection Algorithm$' AND the body following the heading (until next #### or ###) is extracted
    THEN:  Heading exists exactly once; heading appears AFTER current line 318 Unconditional-scan paragraph and BEFORE current line 320 Exemption paragraph; body contains numbered MUST-list (>=4 steps) specifying scan-before-exemption ordering; body contains verbatim positive invariant phrase 'MUST NOT skip CJK scanning for any in-scope file'
    """
    assert TARGET.exists(), f"{TARGET} not found"
    text = TARGET.read_text(encoding="utf-8")
    lines = text.splitlines()

    # Heading exists exactly once
    matches = list(HEADING_RE.finditer(text))
    assert len(matches) == 1, (
        f"Expected exactly 1 '#### Active CJK Detection Algorithm' heading, "
        f"found {len(matches)}"
    )

    heading_line_idx = next(i for i, ln in enumerate(lines)
                            if ln == "#### Active CJK Detection Algorithm")

    # Positional constraints
    before_idx = next((i for i, ln in enumerate(lines) if ANCHOR_BEFORE in ln), -1)
    after_idx = next((i for i, ln in enumerate(lines) if ANCHOR_AFTER in ln), -1)
    assert before_idx >= 0, f"Anchor BEFORE not found: {ANCHOR_BEFORE!r}"
    assert after_idx >= 0, f"Anchor AFTER not found: {ANCHOR_AFTER!r}"
    assert before_idx < heading_line_idx < after_idx, (
        f"Heading at line {heading_line_idx} not between {before_idx} (Unconditional) "
        f"and {after_idx} (Exemption)"
    )

    # Extract body until next ####/### heading
    start = matches[0].end()
    rest = text[start:]
    next_h = NEXT_HEADING_RE.search(rest)
    body = rest[: next_h.start()] if next_h else rest

    # Positive invariant verbatim
    assert POS_INVARIANT in body, (
        f"Positive invariant phrase not present in body: {POS_INVARIANT!r}\n"
        f"Body excerpt:\n{body[:500]}"
    )

    # Numbered MUST-list with >=4 steps
    numbered_steps = re.findall(r"^\s*(\d+)\.\s+", body, re.MULTILINE)
    assert len(numbered_steps) >= 4, (
        f"Expected >=4 numbered steps, found {len(numbered_steps)} in body:\n{body[:500]}"
    )
    # Must-list specifying ordering
    must_count = len(re.findall(r"\bMUST\b", body))
    assert must_count >= 1, f"Body lacks MUST keyword: {body[:300]}"

    # Ordering tokens present in stipulated sequence
    positions = []
    for tok in ORDERING_TOKENS:
        idx = body.find(tok)
        assert idx >= 0, f"Ordering token {tok!r} not found in body"
        positions.append(idx)
    assert positions == sorted(positions), (
        f"Ordering tokens out of order: {list(zip(ORDERING_TOKENS, positions))}"
    )
